/**
 * 工事写真用 DINOv2-small ベクトル（384 次元）
 * @xenova/transformers — 初回利用時にのみ動的 import
 */

export const PHOTO_EMBEDDING_MODEL_VERSION = 'dinov2-small@v1'

const MODEL_ID = 'Xenova/dinov2-small'
const TRANSFORMERS_PKG_VERSION = '2.17.2'
const EMBEDDING_DIM = 384

/** @type {Promise<import('@xenova/transformers')> | null} */
let transformersModPromise = null

function loadTransformersModule() {
  if (!transformersModPromise) {
    transformersModPromise = import('@xenova/transformers').then((mod) => {
      const { env } = mod
      env.allowLocalModels = false
      env.allowRemoteModels = true
      if (env.backends?.onnx?.wasm) {
        env.backends.onnx.wasm.wasmPaths = `https://cdn.jsdelivr.net/npm/@xenova/transformers@${TRANSFORMERS_PKG_VERSION}/dist/`
        env.backends.onnx.wasm.numThreads = 1
      }
      return mod
    })
  }
  return transformersModPromise
}

/** @type {Promise<unknown> | null} */
let extractorPromise = null

async function getExtractor() {
  if (!extractorPromise) {
    extractorPromise = (async () => {
      const { pipeline } = await loadTransformersModule()
      return pipeline('image-feature-extraction', MODEL_ID)
    })()
  }
  return extractorPromise
}

function normalizeL2(arr) {
  let sum = 0
  for (let i = 0; i < arr.length; i++) sum += arr[i] * arr[i]
  const n = Math.sqrt(sum) || 1
  for (let i = 0; i < arr.length; i++) arr[i] /= n
  return arr
}

/**
 * image-feature-extraction が (num_tokens × EMBEDDING_DIM) を平坦化して返す場合、
 * トークン方向で平均して 1 本のベクトルにする（DINOv2-small は 257×384 等）
 * @param {Float32Array} arr
 * @returns {Float32Array}
 */
function toEmbedding384(arr) {
  if (arr.length === EMBEDDING_DIM) {
    return normalizeL2(arr)
  }
  if (arr.length % EMBEDDING_DIM !== 0) {
    throw new Error(`unexpected embedding length ${arr.length}, expected ${EMBEDDING_DIM} or a multiple`)
  }
  const nTok = arr.length / EMBEDDING_DIM
  const out = new Float32Array(EMBEDDING_DIM)
  for (let t = 0; t < nTok; t++) {
    const o = t * EMBEDDING_DIM
    for (let j = 0; j < EMBEDDING_DIM; j++) out[j] += arr[o + j]
  }
  for (let j = 0; j < EMBEDDING_DIM; j++) out[j] /= nTok
  return normalizeL2(out)
}

/**
 * リサイズ済み画像 Blob から DINO 埋め込みを取得（Float32Array, 384）
 * @param {Blob|File} blob
 * @returns {Promise<Float32Array>}
 */
export async function extractPhotoEmbeddingFloat32(blob) {
  const { RawImage } = await loadTransformersModule()
  const extractor = await getExtractor()
  const image = await RawImage.fromBlob(blob)
  const output = await extractor(image, { pooling: 'mean', normalize: true })
  const data = output?.data
  if (!data) {
    throw new Error('embedding output is empty')
  }
  const arr = data instanceof Float32Array ? data : new Float32Array(data)
  return toEmbedding384(arr)
}

/**
 * 複数クロップの DINO 画像ベクトルを平均して L2 正規化する
 * @param {Blob|File} blob
 * @returns {Promise<Float32Array>}
 */
export async function extractPhotoEmbeddingFloat32MultiCrop(blob) {
  const { RawImage } = await loadTransformersModule()
  const extractor = await getExtractor()
  const full = await RawImage.fromBlob(blob)
  const w = full.width
  const h = full.height
  const m = Math.min(w, h)
  if (m < 48) {
    return extractPhotoEmbeddingFloat32(blob)
  }
  const crops = [full]
  const s = Math.max(32, Math.floor(m * 0.85))
  const cx = Math.floor((w - s) / 2)
  const cy = Math.floor((h - s) / 2)
  crops.push(await full.crop([cx, cy, cx + s - 1, cy + s - 1]))
  const q = Math.max(24, Math.floor(m * 0.42))
  crops.push(await full.crop([0, 0, q - 1, q - 1]))
  crops.push(await full.crop([w - q, 0, w - 1, q - 1]))
  crops.push(await full.crop([0, h - q, q - 1, h - 1]))
  crops.push(await full.crop([w - q, h - q, w - 1, h - 1]))

  const acc = new Float32Array(EMBEDDING_DIM)
  let n = 0
  for (const img of crops) {
    const output = await extractor(img, { pooling: 'mean', normalize: true })
    const data = output?.data
    if (!data) continue
    const arr = data instanceof Float32Array ? data : new Float32Array(data)
    let vec
    try {
      vec = toEmbedding384(arr)
    } catch {
      continue
    }
    for (let i = 0; i < EMBEDDING_DIM; i++) acc[i] += vec[i]
    n += 1
  }
  if (n === 0) throw new Error('multi-crop embedding failed')
  for (let i = 0; i < EMBEDDING_DIM; i++) acc[i] /= n
  return normalizeL2(acc)
}

export function getPhotoEmbeddingModelVersion() {
  return PHOTO_EMBEDDING_MODEL_VERSION
}
